class Solution:
    def substringXorQueries(self, s, queries):
        n = len(s)
        max_len = min(n, 30)
        ans = []
        for first, second in queries:
            target = first ^ second
            found = [-1, -1]
            for length in range(1, max_len + 1):
                match = None
                for left in range(0, n - length + 1):
                    val = int(s[left:left + length], 2)
                    if val == target:
                        match = [left, left + length - 1]
                        break
                if match is not None:
                    found = match
                    break
            ans.append(found)
        return ans

