class Solution:
    def substringXorQueries(self, s, queries):
        n = len(s)
        max_len = min(n, 30)
        best = {}
        for length in range(1, max_len + 1):
            for left in range(0, n - length + 1):
                val = int(s[left:left + length], 2)
                if val not in best:
                    best[val] = [left, left + length - 1]
        ans = []
        for first, second in queries:
            target = first ^ second
            ans.append(best.get(target, [-1, -1]))
        return ans

