var substringXorQueries = function(s, queries) {
    const n = s.length;
    const maxLen = Math.min(n, 30);
    const best = new Map();
    for (let length = 1; length <= maxLen; length++) {
        for (let left = 0; left + length <= n; left++) {
            const sub = s.substring(left, left + length);
            const val = parseInt(sub, 2);
            if (!best.has(val)) {
                best.set(val, [left, left + length - 1]);
            }
        }
    }
    const ans = [];
    for (const [first, second] of queries) {
        const target = first ^ second;
        ans.push(best.has(target) ? best.get(target) : [-1, -1]);
    }
    return ans;
};
